                            ?: "Guest User"
                    )
                )
            },
            onLessons = { navigateTo(LessonsFragment()) },
            onCart = { navigateTo(CartFragment()) },
            onProfile = { }
        )
    }
}

package com.example.moozik

import android.content.Intent
import android.graphics.BitmapFactory
